// Tile types for maze grid
export const TILE = {
  EMPTY: 0,   // open path
  WALL: 1,    // solid wall block
  HOLE: 2,    // pit trap — lose a life
  GEM: 3,     // collectible gem
  GOAL: 4,    // level exit
  START: 5,   // spawn position
